// Main Local Storage Manager
class LocalStorageManager {
  static LocalStorageManager? _instance;
  late SharedPreferences _prefs;
  bool _initialized = false;

  // In-memory caches for quick access
  AuthTokens? _cachedTokens;
  UserProfile? _cachedProfile;
  UserPreferences? _cachedPreferences;
  AppConfig? _cachedConfig;

  LocalStorageManager._();

  static LocalStorageManager get instance {
    _instance ??= LocalStorageManager._();
    return _instance!;
  }

  bool get isInitialized => _initialized;

  Future<void> initialize() async {
    if (_initialized) return;
    _prefs = await SharedPreferences.getInstance();
    _initialized = true;
    // Pre-load frequently accessed data into memory
    await _preloadCache();
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError(
          'LocalStorageManager not initialized. Call initialize() first.');
    }
  }

  Future<void> _preloadCache() async {
    _cachedTokens = getAuthTokens();
    _cachedProfile = getUserProfile();
    _cachedPreferences = getUserPreferences();
    _cachedConfig = getAppConfig();
  }

  // ==================== Authentication Tokens ====================

  Future<bool> saveAuthTokens(AuthTokens tokens) async {
    _ensureInitialized();
    final result = await _prefs.setString(
        StorageKeys.authTokens, jsonEncode(tokens.toJson()));
    if (result) {
      _cachedTokens = tokens;
      await _prefs.setBool(StorageKeys.isLoggedIn, true);
    }
    return result;
  }

  AuthTokens? getAuthTokens() {
    _ensureInitialized();
    if (_cachedTokens != null) return _cachedTokens;
    final data = _prefs.getString(StorageKeys.authTokens);
    if (data == null) return null;
    try {
      _cachedTokens =
          AuthTokens.fromJson(jsonDecode(data) as Map<String, dynamic>);
      return _cachedTokens;
    } catch (e) {
      return null;
    }
  }

  String? getAccessToken() {
    final tokens = getAuthTokens();
    if (tokens == null || tokens.isExpired) return null;
    return tokens.accessToken;
  }

  String? getRefreshToken() {
    return getAuthTokens()?.refreshToken;
  }

  bool get isTokenExpired => getAuthTokens()?.isExpired ?? true;

  bool get isTokenAboutToExpire =>
      getAuthTokens()?.isAboutToExpire ?? true;

  Future<bool> clearAuthTokens() async {
    _ensureInitialized();
    _cachedTokens = null;
    await _prefs.setBool(StorageKeys.isLoggedIn, false);
    return _prefs.remove(StorageKeys.authTokens);
  }

  bool get isLoggedIn =>
      _prefs.getBool(StorageKeys.isLoggedIn) ?? false;

  // ==================== User Profile ====================

  Future<bool> saveUserProfile(UserProfile profile) async {
    _ensureInitialized();
    final result = await _prefs.setString(
        StorageKeys.userProfile, jsonEncode(profile.toJson()));
    if (result) _cachedProfile = profile;
    return result;
  }

  UserProfile? getUserProfile() {
    _ensureInitialized();
    if (_cachedProfile != null) return _cachedProfile;
    final data = _prefs.getString(StorageKeys.userProfile);
    if (data == null) return null;
    try {
      _cachedProfile =
          UserProfile.fromJson(jsonDecode(data) as Map<String, dynamic>);
      return _cachedProfile;
    } catch (e) {
      return null;
    }
  }

  Future<bool> updateUserProfile(
