    final current = getUserProfile();
    if (current == null) return false;
    return saveUserProfile(updater(current));
  }

  Future<bool> clearUserProfile() async {
    _ensureInitialized();
    _cachedProfile = null;
    return _prefs.remove(StorageKeys.userProfile);
  }

  // ==================== User Preferences ====================

  Future<bool> saveUserPreferences(UserPreferences preferences) async {
    _ensureInitialized();
    final result = await _prefs.setString(
