  String? getCachedContent(String key, {bool ignoreExpiry = false}) {
    _ensureInitialized();
    final data = _prefs.getString('${StorageKeys.cachePrefix}$key');
    if (data == null) return null;
    try {
      final cached =
          CachedContent.fromJson(jsonDecode(data) as Map<String, dynamic>);
      if (!ignoreExpiry && cached.isExpired) {
        removeCachedContent(key);
        return null;
      }
      return cached.data;
    } catch (e) {
      return null;
    }
  }

  Map<String, dynamic>? getCachedJsonContent(String key,
      {bool ignoreExpiry = false}) {
    final data = getCachedContent(key, ignoreExpiry: ignoreExpiry);
    if (data == null) return null;
    try {
      return jsonDecode(data) as Map<String, dynamic>;
    } catch (e) {
      return null;
    }
  }

  List<dynamic>? getCachedListContent(String key,
      {bool ignoreExpiry = false}) {
    final data = getCachedContent(key, ignoreExpiry: ignoreExpiry);
    if (data == null) return null;
    try {
      return jsonDecode(data) as List<dynamic>;
    } catch (e) {
      return null;
    }
  }

  bool isCacheValid(String key) {
    _ensureInitialized();
    final data = _prefs.getString('${StorageKeys.cachePrefix}$key');
    if (data == null) return false;
    try {
      final cached =
          CachedContent.fromJson(jsonDecode(data) as Map<String, dynamic>);
      return !cached.isExpired;
    } catch (e) {
      return false;
    }
  }

  Future<bool> removeCachedContent(String key) async {
    _ensureInitialized();
    return _prefs.remove('${StorageKeys.cachePrefix}$key');
  }

  Future<void> clearAllCache() async {
    _ensureInitialized();
    final keys = _prefs.getKeys();
    for (final key in keys) {
      if (key.startsWith(StorageKeys.cachePrefix)) {
        await _prefs.remove(key);
      }
    }
  }

  Future<void> clearExpiredCache() async {
    _ensureInitialized();
    final keys = _prefs.getKeys();
    for (final key in keys) {
      if (key.startsWith(StorageKeys.cachePrefix)) {
        final data = _prefs.getString(key);
        if (data != null) {
          try {
            final cached = CachedContent.fromJson(
                jsonDecode(data) as Map<String, dynamic>);
            if (cached.isExpired) {
              await _prefs.remove(key);
            }
          } catch (e) {
            await _prefs.remove(key);
          }
        }
      }
    }
  }

