  // ==================== Pending Actions (for offline sync) ====================

  Future<bool> addPendingAction(Map<String, dynamic> action) async {
    _ensureInitialized();
    final actions = getPendingActions();
    action['timestamp'] = DateTime.now().toIso8601String();
    action['id'] = DateTime.now().millisecondsSinceEpoch.toString();
    actions.add(action);
    return _prefs.setString(
        StorageKeys.pendingActionsKey, jsonEncode(actions));
  }

  List<Map<String, dynamic>> getPendingActions() {
    _ensureInitialized();
    final data = _prefs.getString(StorageKeys.pendingActionsKey);
    if (data == null) return [];
    try {
      return (jsonDecode(data) as List)
          .map((e) => e as Map<String, dynamic>)
          .toList();
    } catch (e) {
      return [];
    }
  }

  Future<bool> removePendingAction(String actionId) async {
    _ensureInitialized();
    final actions = getPendingActions();
    actions.removeWhere((a) => a['id'] == actionId);
    return _prefs.setString(
        StorageKeys.pendingActionsKey, jsonEncode(actions));
  }

  Future<bool> clearPendingActions() async {
