  Future<void> logout() async {
    _ensureInitialized();
    await clearAuthTokens();
    await clearUserProfile();
    await clearPendingActions();
    await clearAllCache();
    await clearAllOfflineData();
    _cachedTokens = null;
    _cachedProfile = null;
    // Keep preferences and app config
  }

