  // ==================== Storage Stats ====================

  Map<String, dynamic> getStorageStats() {
    _ensureInitialized();
    final keys = _prefs.getKeys();
    int cacheCount = 0;
    int offlineCount = 0;
    int otherCount = 0;

    for (final key in keys) {
      if (key.startsWith(StorageKeys.cachePrefix)) {
        cacheCount++;
      } else if (key.startsWith(StorageKeys.offlineDataPrefix)) {
        offlineCount++;
      } else {
        otherCount++;
      }
    }

    return {
      'totalKeys': keys.length,
      'cacheEntries': cacheCount,
      'offlineEntries': offlineCount,
      'otherEntries': otherCount,
      'isLoggedIn': isLoggedIn,
      'hasAuthTokens': getAuthTokens() != null,
      'hasUserProfile': getUserProfile() != null,
      'pendingActions': pendingActionsCount,
      'lastSyncTime': getLastSyncTime()?.toIso8601String(),
    };
  }
