// Example usage and demonstration
Future<void> main() async {
  // Initialize the storage manager
  final storage = LocalStorageManager.instance;
  await storage.initialize();

  // Save auth tokens
  await storage.saveAuthTokens(AuthTokens(
    accessToken: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...',
    refreshToken: 'refresh_token_here',
    expiresAt: DateTime.now().add(const Duration(hours: 1)),
    tokenType: 'Bearer',
  ));

  // Check authentication
  print('Is logged in: ${storage.isLoggedIn}');
  print('Access token: ${storage.getAccessToken()}');
  print('Token expired: ${storage.isTokenExpired}');

  // Save user profile
  await storage.saveUserProfile(UserProfile(
    id: 'user_123',
    name: 'John Doe',
    email: 'john@example.com',
    avatarUrl: 'https://example.com/avatar.jpg',
    phone: '+1234567890',
    metadata: {'role': 'admin', 'department': 'engineering'},
  ));

  // Read user profile
  final profile = storage.getUserProfile();
  print('User: ${profile?.name} (${profile?.email})');

  // Update user profile
  await storage.updateUserProfile(
      (current) => current.copyWith(name: 'John Updated'));

  // Save and read preferences
  await storage.setThemeMode('dark');
  await storage.setLanguage('en');
  await storage.setNotificationsEnabled(true);
  await storage.setBiometricEnabled(false);
  await storage.setFontSize(16);

  print('Theme: ${storage.getThemeMode()}');
  print('Language: ${storage.getLanguage()}');
  print('Notifications: ${storage.getNotificationsEnabled()}');

  // Save app configuration
  await storage.saveAppConfig(AppConfig(
    apiBaseUrl: 'https://api.myapp.com/v2',
    appVersion: '2.1.0',
    maintenanceMode: false,
    sessionTimeoutMinutes: 60,
    featureFlags: {
      'dark_mode': true,
      'beta_features': false,
      'push_notifications': true,
    },
  ));

  print('API URL: ${storage.getApiBaseUrl()}');
  print('Dark mode enabled: ${storage.isFeatureEnabled('dark_mode')}');

  // Cache content
  await storage.cacheContent('home_feed', '{"posts": []}',
      ttl: const Duration(minutes: 30));

  await storage.cacheJsonContent(
      'user_settings', {'theme': 'dark', 'lang': 'en'},
      ttl: const Duration(hours: 24));

  await storage.cacheListContent('notifications', [
    {'id': 1, 'message': 'Welcome!'},
    {'id': 2, 'message': 'New update available'},
  ], ttl: const Duration(minutes: 15));

  // Read cached content
  final feed = storage.getCachedContent('home_feed');
  print('Cached feed: $feed');
  print('Cache valid: ${storage.isCacheValid('home_feed')}');

  final settings = storage.getCachedJsonContent('user_settings');
  print('Cached settings: $settings');

  final notifications = storage.getCachedListContent('notifications');
  print('Cached notifications: $notifications');

  // Offline data storage
  await storage.saveOfflineData('draft_post', {
    'title': 'My Draft',
    'content': 'This was written offline',
    'createdAt': DateTime.now().toIso8601String(),
  });

  await storage.saveOfflineListData('offline_messages', [
    {'to': 'user_456', 'text': 'Hello!', 'sent': false},
    {'to': 'user_789', 'text': 'Hi there!', 'sent': false},
  ]);

  final draft = storage.getOfflineData('draft_post');
  print('Draft: $draft');

  final messages = storage.getOfflineListData('offline_messages');
  print('Offline messages: $messages');

  // Pending actions for sync
  await storage.addPendingAction({
    'type': 'create_post',
    'data': {'title': 'New Post', 'body': 'Post content'},
  });

  await storage.addPendingAction({
    'type': 'update_profile',
    'data': {'name': 'Jane Doe'},
  });

  print('Pending actions: ${storage.pendingActionsCount}');
  final pending = storage.getPendingActions();
  for (final action in pending) {
    print('  Action: ${action['type']} at ${action['timestamp']}');
  }

  // First launch check
  if (storage.isFirstLaunch) {
    print('First time launch - show onboarding');
    await storage.setFirstLaunchComplete();
  }

  // Last sync time
  await storage.setLastSyncTime(DateTime.now());
  print('Last sync: ${storage.getLastSyncTime()}');

  // Storage stats
  print('Storage stats: ${storage.getStorageStats()}');

  // Clean up expired cache
  await storage.clearExpiredCache();

  // Logout - clears auth, profile, cache, offline data, pending actions
  // but keeps preferences and app config
  // await storage.logout();

  // Full clear
  // await storage.clearAll();
}